import './index.css';

import {
  useState
} from 'react';

import {
  createNote
} from '../../services/noteService';

function CoordinatorNotes() {

  const [formData, setFormData] =
    useState({

      title: '',
      message: ''

    });

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await createNote(formData);

      alert(
        'Note Sent Successfully'
      );

      setFormData({

        title: '',
        message: ''

      });

    } catch (error) {

      console.log(error);

      alert(
        error.response?.data?.message
      );

    }

  };

  return (

    <div className="notes-page">

      <h1>
        Coordinator Notes
      </h1>

      <form
        className="notes-form"
        onSubmit={handleSubmit}
      >

        <input
          type="text"
          name="title"
          placeholder="Enter Title"
          value={formData.title}
          onChange={handleChange}
          required
        />

        <textarea
          name="message"
          placeholder="Enter Message"
          value={formData.message}
          onChange={handleChange}
          required
        />

        <button type="submit">

          Send Note

        </button>

      </form>

    </div>

  );

}

export default CoordinatorNotes;
